import{_ as e,o as a,c as r,a4 as n}from"./chunks/framework.BybBnFXO.js";const u=JSON.parse('{"title":"砂金效应","description":"","frontmatter":{"title":"砂金效应","phenomenon":"aventurescence"},"headers":[],"relativePath":"zh/optical-phenomena/aventurescence.md","filePath":"zh/optical-phenomena/aventurescence.md","lastUpdated":1784176423000}'),o={name:"zh/optical-phenomena/aventurescence.md"};function d(l,t,i,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="砂金效应" tabindex="-1">砂金效应 <a class="header-anchor" href="#砂金效应" aria-label="Permalink to &quot;砂金效应&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>砂金效应是当宝石内部含有大量小而平的金属矿物薄片（最常见为赤 铁矿 / 铜片）时，光从这些薄片反射形成闪烁的金属光泽。最著名的 是：</p><ul><li><strong>日光石 (Sunstone)</strong> —— 长石族中含赤铁矿 / 针铁矿薄片</li><li><strong>砂金石 (Aventurine)</strong> —— 石英中含铬云母 / 赤铁矿薄片（绿色、棕色变种）</li><li><strong>东陵玉</strong> —— 与砂金石同类，绿色最常见 薄片越大、越反光，效果越明显。</li></ul><h2 id="机制" tabindex="-1">机制 <a class="header-anchor" href="#机制" aria-label="Permalink to &quot;机制&quot;">​</a></h2><p>薄片反射：宝石结晶过程中赤铁矿（Fe₂O₃）或针铁矿（FeO(OH)） 沿特定方向析出为细小六边形或圆形薄片，每片尺寸约 0.1–1 mm。 当光从不同方向入射，各薄片依次闪烁形成&quot;星光&quot;般的金属闪烁 效果。绿色砂金石中的铬云母反射绿色光，红/棕色来自赤铁矿。</p><h2 id="示例宝石" tabindex="-1">示例宝石 <a class="header-anchor" href="#示例宝石" aria-label="Permalink to &quot;示例宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>包裹体薄片</th><th>宿主矿物</th></tr></thead><tbody><tr><td>Sunstone (Oregon) / 日光石</td><td>copper / hematite</td><td>Feldspar (oligoclase / labradorite)</td></tr><tr><td>Aventurine Quartz (green) / 砂金石</td><td>chrome-mica / fuchsite</td><td>Quartz</td></tr><tr><td>Aventurine Quartz (red-brown) / 砂金石</td><td>hematite</td><td>Quartz</td></tr><tr><td>Imperial Sunstone / 帝王日光石</td><td>large copper platelets</td><td>Feldspar</td></tr></tbody></table><p><em>详见<a href="./intro.html">光学现象总览</a>。</em></p>',9)])])}const m=e(o,[["render",d]]);export{u as __pageData,m as default};
